"""
Data structures for pipeline tasks and parameters.
"""
from dataclasses import dataclass, field
from typing import Optional, Dict, List, Any, Union
from enum import Enum
import json
import os

class ParamType(Enum):
    STRING = "string"
    INT = "int"
    FLOAT = "float"
    BOOL = "bool"
    LIST = "list"

@dataclass
class Parameter:
    name: str
    param_type: ParamType
    default_value: Optional[Any] = None
    has_default: bool = False

    @classmethod
    def from_def(cls, name: str, type_str: str, default_value: Optional[str] = None) -> 'Parameter':
        type_map = {
            "string": ParamType.STRING,
            "int": ParamType.INT,
            "float": ParamType.FLOAT,
            "bool": ParamType.BOOL,
        }

        if type_str.startswith("list["):
            param_type = ParamType.LIST
            inner_type = type_str[5:-1]  # extract type inside []
        else:
            param_type = type_map.get(type_str)
            if param_type is None:
                raise ValueError(f"Unknown parameter type: {type_str}")

        parsed_default = None
        has_default = default_value is not None

        if has_default:
            parsed_default = cls._parse_default(default_value, param_type, type_str)

        return cls(name=name, param_type=param_type, default_value=parsed_default, has_default=has_default)

    @staticmethod
    def _parse_default(value: str, param_type: ParamType, type_str: str) -> Any:
        value = value.strip().strip('"').strip("'")

        if param_type == ParamType.STRING:
            return value
        elif param_type == ParamType.INT:
            return int(value)
        elif param_type == ParamType.FLOAT:
            return float(value)
        elif param_type == ParamType.BOOL:
            return value.upper() == "TRUE"
        elif param_type == ParamType.LIST:
            # Parse list like [value1, value2, value3]
            inner = type_str[5:-1]
            if inner == "string":
                # Remove brackets and split by comma
                items = value.strip("[]").split(",")
                return [item.strip().strip('"').strip("'") for item in items if item.strip()]
            elif inner == "int":
                items = value.strip("[]").split(",")
                return [int(item.strip()) for item in items if item.strip()]
            elif inner == "float":
                items = value.strip("[]").split(",")
                return [float(item.strip()) for item in items if item.strip()]
            elif inner == "bool":
                items = value.strip("[]").split(",")
                return [item.strip().upper() == "TRUE" for item in items if item.strip()]
        return value

@dataclass
class SuccessCriterion:
    name: str
    expression: str

@dataclass
class Task:
    name: str
    params: List[Parameter] = field(default_factory=list)
    run: Optional[str] = None
    success: List[SuccessCriterion] = field(default_factory=list)
    requires: Optional[str] = None
    output: Optional[str] = None
    timeout: Optional[float] = None

    # Resolved fields
    resolved_params: Dict[str, Any] = field(default_factory=dict, repr=False)
    job_id: Optional[int] = None
    parent: Optional[int] = None

@dataclass
class JobResult:
    job_id: int
    task: str
    params: Dict[str, Any]
    stdout: str
    stderr: str
    timed_out: bool
    success: Dict[str, bool]
    output: Optional[str]
    exit_code: int
    parent: Optional[int]
    duration: float

    def to_jsonl(self) -> str:
        # Cleanup: \u2018 → '\n        stdout_clean = self.stdout.replace("\u2018", "'").replace("\u2019", "'")
        stderr_clean = self.stderr.replace("\u2018", "'").replace("\u2019", "'")

        return json.dumps({
            "job_id": self.job_id,
            "task": self.task,
            "params": self.params,
            "stdout": stdout_clean,
            "stderr": stderr_clean,
            "timed_out": self.timed_out,
            "success": self.success,
            "output": self.output,
            "exit_code": self.exit_code,
            "parent": self.parent,
            "duration": self.duration
        })

@dataclass
class Config:
    entry: Optional[str] = None
    clean_cwd: bool = False
    env: Dict[str, str] = field(default_factory=dict)

"""
TOML config parser.
"""
import toml
from typing import Dict, Optional, Tuple, Any, List
from pipeline_types import Config
from pipeline_parser import ParseError

def parse_config_file(config_path: str) -> Config:
    """Parse a TOML config file."""
    try:
        with open(config_path, 'r') as f:
            data = toml.load(f)
    except toml.TomlDecodeError as e:
        raise ParseError(f"Invalid TOML syntax: {str(e)}")
    except FileNotFoundError:
        raise ParseError(f"Config file not found: {config_path}")

    config = Config()

    # Parse entry task
    if 'entry' in data:
        entry = data['entry']
        config.entry = entry

    # Parse clean_cwd
    if 'clean_cwd' in data:
        config.clean_cwd = data['clean_cwd']

    # Parse environment variables
    if 'env' in data:
        if isinstance(data['env'], dict):
            config.env = {k: str(v) for k, v in data['env'].items()}
        else:
            raise ParseError("env must be a table in config")

    return config


def parse_entry_task(entry_str: str) -> Tuple[str, Dict[str, Any]]:
    """
    Parse an entry task string like 'main' or 'main(1, x=2)'.
    Returns (task_name, params_dict).
    """
    # Check if task call has parameters
    parens_start = entry_str.find('(')
    if parens_start == -1:
        return entry_str.strip(), {}

    if not entry_str.endswith(')'):
        raise ParseError(f"Invalid entry task: unclosed parenthesis in '{entry_str}'")

    task_name = entry_str[:parens_start].strip()
    args_str = entry_str[parens_start + 1:-1]

    if not args_str.strip():
        return task_name, {}

    # Parse arguments
    params = {}
    parts = []
    current = ""
    in_quotes = False
    quote_char = None
    depth = 0

    for ch in args_str:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            if in_quotes:
                quote_char = ch
            else:
                quote_char = None
            current += ch
        elif not in_quotes:
            if ch == '(' or ch == '[':
                depth += 1
                current += ch
            elif ch == ')' or ch == ']':
                depth -= 1
                current += ch
            elif ch == ',' and depth == 0:
                parts.append(current.strip())
                current = ""
            else:
                current += ch
        else:
            current += ch

    if current.strip():
        parts.append(current.strip())

    for part in parts:
        part = part.strip()
        if not part:
            continue

        if '=' in part:
            # Named argument
            key, val = part.split('=', 1)
            key = key.strip()
            val = val.strip()
            # Remove quotes if present
            if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
                val = val[1:-1]
            # Try to parse value
            if val.isdigit():
                val = int(val)
            elif val.replace('.', '').isdigit():
                val = float(val)
            elif val.upper() in ('TRUE', 'FALSE'):
                val = val.upper() == 'TRUE'
            params[key] = val
        else:
            # Positional argument
            val = part
            if val.isdigit():
                val = int(val)
            elif val.replace('.', '').isdigit():
                val = float(val)
            elif val.upper() in ('TRUE', 'FALSE'):
                val = val.upper() == 'TRUE'
            params[len(params)] = val

    return task_name, params

"""
Pipeline file parser - simplified robust approach.
"""
import re
from typing import List, Dict, Optional, Tuple, Any
from pipeline_types import Task, Parameter, SuccessCriterion, ParamType


class ParseError(Exception):
    """Syntax error in pipeline file."""

    def __init__(self, message: str, position: int = -1, line: int = -1):
        full_msg = f"SYNTAX_ERROR:{message}"
        if position != -1:
            full_msg += f" at position {position}"
        if line != -1:
            full_msg += f" (line {line})"
        super().__init__(full_msg)
        self.message = message


def find_matching_brace(text: str, start: int) -> int:
    """Find the matching closing brace for the opening brace at start position."""
    if text[start] != '{':
        raise ParseError("Expected '{'")

    depth = 1
    pos = start + 1
    while pos < len(text) and depth > 0:
        if text[pos] == '{':
            depth += 1
        elif text[pos] == '}':
            depth -= 1
        pos += 1

    if depth != 0:
        raise ParseError("Unclosed block")

    return pos - 1


def strip_value(s: str) -> str:
    """Strip and unquote a string value."""
    s = s.strip()
    if s and ((s.startswith('"') and s.endswith('"')) or (s.startswith("'") and s.endswith("'"))):
        s = s[1:-1]
    return s


def parse_pipeline_file(content: str) -> List[Task]:
    """Parse a pipeline file and return the list of tasks."""
    # Remove comments
    lines = content.split('\n')
    cleaned_lines = []
    for line in lines:
        if '//' in line:
            line = line[:line.index('//')]
        cleaned_lines.append(line)
    content = '\n'.join(cleaned_lines)

    tasks = []

    # Pattern: task <name> { content }
    task_pattern = r'\btask\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\{'

    pos = 0
    while pos < len(content):
        match = re.search(task_pattern, content[pos:])
        if not match:
            break

        task_start = pos + match.start()
        task_name = match.group(1)
        brace_start = task_start + match.end() - 1
        brace_end = find_matching_brace(content, brace_start)

        task_text = content[brace_start + 1:brace_end].strip()

        try:
            task = parse_task_body(task_name, task_text)
            tasks.append(task)
        except ParseError as e:
            raise ParseError(f"Error parsing task '{task_name}': {e.message}")

        pos = brace_end + 1

    return tasks


def parse_task_body(name: str, body: str) -> Task:
    """Parse a task body."""
    task = Task(name=name)

    # Split body into blocks using braces tracking
    blocks = extract_blocks(body)

    for block_name, block_content in blocks.items():
        if block_name == 'params':
            task.params = parse_params(block_content)
        elif block_name == 'run':
            task.run = block_content.strip()
        elif block_name == 'success':
            task.success = parse_success(block_content)
        elif block_name == 'requires':
            task.requires = block_content.strip()
        elif block_name == 'output':
            task.output = strip_value(block_content)
        elif block_name == 'timeout':
            task.timeout = float(block_content.strip())

    return task


def extract_blocks(body: str) -> Dict[str, str]:
    """Extract named blocks from a body text."""
    blocks = {}
    pos = 0

    while pos < len(body):
        # Skip whitespace
        while pos < len(body) and body[pos].isspace():
            pos += 1

        if pos >= len(body):
            break

        # Look for a block name followed by colon
        for keyword in ['params:', 'run:', 'success:', 'requires:', 'output:', 'timeout:']:
            if body.startswith(keyword, pos):
                block_name = keyword.rstrip(':')
                pos += len(keyword)

                # Skip whitespace
                while pos < len(body) and body[pos].isspace():
                    pos += 1

                # Extract content based on syntax
                if block_name in ['params', 'run', 'success', 'requires']:
                    # These have braces
                    if pos < len(body) and body[pos] == '{':
                        content_end = find_matching_brace(body, pos)
                        content = body[pos + 1:content_end].strip()
                        blocks[block_name] = content
                        pos = content_end + 1
                    else:
                        # Check for shorthand run without braces: run { ... }
                        while pos < len(body) and body[pos].isspace():
                            pos += 1
                        if pos < len(body) and body[pos] == '{':
                            content_end = find_matching_brace(body, pos)
                            content = body[pos + 1:content_end].strip()
                            blocks[block_name] = content
                            pos = content_end + 1
                elif block_name == 'output':
                    # output: "value"
                    end_pos = pos
                    while end_pos < len(body) and body[end_pos] not in ('\n', ';'):
                        end_pos += 1
                    content = body[pos:end_pos].strip()
                    blocks[block_name] = content
                    pos = end_pos
                elif block_name == 'timeout':
                    # timeout: 60.5
                    end_pos = pos
                    while end_pos < len(body) and body[end_pos] not in ('\n', ';'):
                        end_pos += 1
                    content = body[pos:end_pos].strip()
                    blocks[block_name] = content
                    pos = end_pos

                break
        else:
            pos += 1

    return blocks


def parse_params(text: str) -> List[Parameter]:
    """Parse parameter definitions."""
    params = []

    # Split by semicolons or newlines, respecting quoted strings
    segments = []
    current = ""
    in_quotes = False
    quote_char = None

    for ch in text:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            if in_quotes:
                quote_char = ch
            else:
                quote_char = None
            current += ch
        elif ch == ';' and not in_quotes:
            if current.strip():
                segments.append(current.strip())
            current = ""
        else:
            current += ch

    if current.strip():
        segments.append(current.strip())

    # Actually, let's use comma splitting since it looks like: a: int, b: string = "default"
    segments = []
    current = ""

    for ch in text:
        if ch == ',' and not any([in_quotes]):
            if current.strip():
                segments.append(current.strip())
            current = ""
        else:
            current += ch
    if current.strip():
        segments.append(current.strip())

    # Let's re-implement with simple comma splitting
    # Pattern: <name>: <type> [= <default-value>];
    segments = []
    current = ""
    in_quotes = False
    quote_char = None

    for ch in text:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            if in_quotes:
                quote_char = ch
            else:
                quote_char = None
            current += ch
        elif ch == ',' and not in_quotes:
            if current.strip():
                segments.append(current.strip())
            current = ""
        else:
            current += ch

    if current.strip():
        segments.append(current.strip())

    for segment in segments:
        if not segment.strip():
            continue

        # Parse: param_name: type [= default]
        # Split at the first ':'
        if ':' not in segment:
            raise ParseError(f"Invalid parameter definition: {segment}")

        name_part, type_and_default = segment.split(':', 1)
        name = name_part.strip()

        # Split type and default
        type_str = type_and_default.strip()
        default_value = None
        has_default = False

        if '=' in type_str:
            parts = type_str.split('=', 1)
            type_str = parts[0].strip()
            default_str = parts[1].strip().rstrip(';')
            default_value = parse_default_value(default_str)
            has_default = True

        # Remove trailing semicolon if present
        type_str = type_str.rstrip(';').strip()

        # Handle list types
        if type_str == 'list':
            # Check for [...] after
            match = re.search(r'list\s*\[([a-zA-Z_][a-zA-Z0-9_]*)\]', segment)
            if match:
                inner_type = match.group(1)
                param_type = ParamType.LIST
                param = Parameter(name=name, param_type=param_type, default_value=default_value, has_default=has_default)
                params.append(param)
                continue

        # Regular types
        type_map = {
            'string': ParamType.STRING,
            'int': ParamType.INT,
            'float': ParamType.FLOAT,
            'bool': ParamType.BOOL,
        }

        if type_str not in type_map:
            raise ParseError(f"Unknown parameter type: {type_str}")

        param = Parameter(name=name, param_type=type_map[type_str], default_value=default_value, has_default=has_default)
        params.append(param)

    return params


def parse_default_value(value_str: str) -> Any:
    """Parse a default value string into its Python representation."""
    value_str = value_str.strip()

    # Try boolean
    if value_str.upper() == 'TRUE':
        return True
    if value_str.upper() == 'FALSE':
        return False

    # Try quoted strings
    if value_str.startswith('"') and value_str.endswith('"'):
        return value_str[1:-1]
    if value_str.startswith("'") and value_str.endswith("'"):
        return value_str[1:-1]

    # Try integer
    if value_str.isdigit() or (value_str.startswith('-') and value_str[1:].isdigit()):
        return int(value_str)

    # Try float
    try:
        f = float(value_str)
        if f == float('inf') or f == float('-inf') or value_str == 'nan':
            return f
        return f
    except ValueError:
        pass

    return value_str


def parse_success(text: str) -> List[SuccessCriterion]:
    """Parse success criteria block."""
    criteria = []

    pos = 0
    text_len = len(text)

    while pos < text_len:
        # Skip whitespace
        while pos < text_len and text[pos].isspace():
            pos += 1

        if pos >= text_len:
            break

        # Look for: <name>: { <expression> }
        # Find the name
        name_match = re.match(r'([a-zA-Z_][a-zA-Z0-9_]*)\s*:', text[pos:])
        if name_match:
            name = name_match.group(1)
            colon_pos = pos + name_match.end()

            # Skip whitespace after colon
            while colon_pos < text_len and text[colon_pos].isspace():
                colon_pos += 1

            if colon_pos < text_len and text[colon_pos] == '{':
                brace_end = find_matching_brace(text, colon_pos)
                expr = text[colon_pos + 1:brace_end].strip()
                criteria.append(SuccessCriterion(name, expr))
                pos = brace_end + 1
            else:
                pos += 1
        else:
            pos += 1

    return criteria


def parse_call_args(args_str: str) -> Dict[str, Any]:
    """Parse arguments from a task call like `1, x=2` or `name=value`."""
    args = {}

    if not args_str.strip():
        return args

    # Simple comma splitting
    current = ""
    in_quotes = False
    quote_char = None
    depth = 0  # For nested ()

    for ch in args_str:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            if in_quotes:
                quote_char = ch
            else:
                quote_char = None
            current += ch
        elif not in_quotes:
            if ch == '(':
                depth += 1
                current += ch
            elif ch == ')':
                depth -= 1
                current += ch
            elif ch == ',' and depth == 0:
                if current.strip():
                    add_arg(current.strip(), args)
                current = ""
            else:
                current += ch
        else:
            current += ch

    if current.strip():
        add_arg(current.strip(), args)

    return args


def add_arg(arg: str, args: Dict):
    """Add a parsed argument to the args dict."""
    arg = arg.strip()

    if '=' in arg:
        key, val = arg.split('=', 1)
        key = key.strip()
        val = val.strip()

        # Remove quotes
        if val.startswith('"') and val.endswith('"'):
            val = val[1:-1]
        elif val.startswith("'") and val.endswith("'"):
            val = val[1:-1]

        # Type inference
        if val.isdigit():
            val = int(val)
        elif val.replace('.', '').isdigit():
            try:
                val = float(val)
            except ValueError:
                pass
        elif val.upper() in ('TRUE', 'FALSE'):
            val = val.upper() == 'TRUE'

        args[key] = val
    else:
        # Positional argument
        val = arg
        if val.isdigit():
            val = int(val)
        elif val.replace('.', '').isdigit():
            try:
                val = float(val)
            except ValueError:
                pass
        elif val.upper() in ('TRUE', 'FALSE'):
            val = val.upper() == 'TRUE'

        args[len(args)] = val

"""
Main orchestrator for pipeline execution.
Handles task scheduling, dependency resolution, and execution flow.
"""
import time
from pathlib import Path
from typing import Dict, List, Optional, Set
from pipeline_types import Task, TaskDict, JobResult, Config
from pipeline_parser import parse_pipeline_file, ParseError
from config_parser import parse_config_file, parse_entry_task
from executor import TaskExecutor
from evaluator import ExpressionEvaluator, EvaluationError


class Orchestrator:
    """
    Orchestrates pipeline execution: resolves dependencies and schedules tasks.
    """

    def __init__(self, workspace: Path, output_dir: Path,
                 config: Optional[Config] = None, env: Optional[Dict[str, str]] = None):
        self.workspace = workspace
        self.output_dir = output_dir
        self.config = config or Config()
        self.env = env or {}

        # Update environment with config
        self.env.update(self.config.env)

        self.executor = TaskExecutor(workspace, output_dir, self.env)

        # Task registry - name -> Task object
        self.tasks: Dict[str, Task] = {}

        # Track which tasks have been executed with which params
        self.executed_tasks: Dict[str, List[JobResult]] = {}

        # Track tasks that are currently running
        self.running_tasks: Set[str] = set()

        # Job results indexed by task name
        self.job_results: Dict[str, JobResult] = {}

    def register_tasks(self, parsed_tasks: List[Task]):
        """Register tasks from parsed pipeline."""
        for task in parsed_tasks:
            if task.name in self.tasks:
                raise ValueError(f"Duplicate task definition: {task.name}")
            self.tasks[task.name] = task

    def resolve_entry_task(self, entry_spec: Optional[str] = None) -> tuple:
        """
        Determine which task is the entry point and with what parameters.
        Returns (task_name, params_dict).
        """
        if entry_spec:
            return parse_entry_task(entry_spec)

        # Look for 'main' task as default entry point
        if 'main' in self.tasks:
            return 'main', {}

        # If there's only one task, use that
        if len(self.tasks) == 1:
            task_name = list(self.tasks.keys())[0]
            return task_name, {}

        raise ValueError("No entry task specified and no default 'main' or single task found")

    def _resolve_params_from_call(self, task: Task, call_params: Dict[str, Any]) -> Dict[str, Any]:
        """
        Resolve parameters from a task call, applying defaults and type checking.
        """
        resolved = {}

        # Map call params to parameter definitions
        param_by_position = {}  # index -> param name
        param_by_name = {}  # name -> param def

        for i, param_def in enumerate(task.params):
            if param_def.has_default:
                resolved[param_def.name] = param_def.default_value
            param_by_name[param_def.name] = param_def

        # Apply call params
        for key, value in call_params.items():
            if isinstance(key, int):
                # Positional param
                if key < len(task.params):
                    param_name = task.params[key].name
                    param_def = task.params[key]
                    resolved[param_name] = self._cast_value(value, param_def)
            else:
                # Named param
                if key in param_by_name:
                    param_def = param_by_name[key]
                    resolved[key] = self._cast_value(value, param_def)
                else:
                    raise ValueError(f"Unknown parameter: {key}")

        return resolved

    def _cast_value(self, value: str, param_def) -> Any:
        """Cast a value from the task call to the parameter's expected type."""
        if param_def.param_type.name == 'STRING':
            return str(value)
        elif param_def.param_type.name == 'INT':
            try:
                return int(value)
            except ValueError:
                raise ValueError(f"Invalid integer value: {value}")
        elif param_def.param_type.name == 'FLOAT':
            try:
                return float(value)
            except ValueError:
                raise ValueError(f"Invalid float value: {value}")
        elif param_def.param_type.name == 'BOOL':
            return str(value).upper() in ('TRUE', '1', 'YES', 'T')
        elif param_def.param_type.name == 'LIST':
            # Lists from task calls are tricky - assume string representation
            return [v.strip().strip('"').strip("'") for v in value.split(',')] if value else []

        return value

    def resolve_dependencies(self, task: Task, params: Dict[str, Any]) -> List[JobResult]:
        """
        Resolve task dependencies based on the requires block.
        Returns a list of job results from required tasks.
        """
        if not task.requires:
            return []

        # We need to parse the requires expression and execute sub-tasks
        # For now, use a simple parser for requires
        return self._parse_and_execute_requires(task, params)

    def _parse_and_execute_requires(self, task: Task, params: Dict[str, Any]) -> List[JobResult]:
        """
        Parse and execute requires block expressions.
        Returns a list of job results from required tasks.
        """
        requires_text = task.requires

        if not requires_text:
            return []

        # Simple parser for requires block
        # We'll handle:
        # - task(name, params)
        # - fails(task(name, params))
        # - for loops
        # - if/else conditions

        results = []
        pos = 0
        text = requires_text.strip()

        # Skip opening brace if present
        if text.startswith('{'):
            text = text[1:].strip()

        context = {
            '_completed_tasks': set(self.executor.completed_tasks.keys()),
            '_failed_tasks': [],
        }

        while pos < len(text):
            # Skip whitespace and newlines
            while pos < len(text) and text[pos].isspace():
                pos += 1

            if pos >= len(text):
                break

            # Check for 'fails(' function
            if text.startswith('fails(', pos):
                # Parse inside fails
                paren_idx = text.find('(', pos)
                brace_depth = 1
                paren_idx += 1
                start = paren_idx

                while brace_depth > 0:
                    if text[paren_idx] == '(':
                        brace_depth += 1
                    elif text[paren_idx] == ')':
                        brace_depth -= 1
                    paren_idx += 1

                task_call = text[start:paren_idx-1].strip()

                # Execute the task even if it fails
                try:
                    sub_result = self._execute_task_from_call(task_call, params)
                    # Don't stop the pipeline even if this task fails
                    results.append(sub_result)
                except Exception as e:
                    # Task execution error
                    pass

                pos = paren_idx
                continue

            # Check for task call
            identifier = ''
            idx = pos
            while idx < len(text) and (text[idx].isalnum() or text[idx] == '_'):
                idx += 1

            identifier = text[pos:idx]

            if identifier and identifier in self.tasks:
                # This is a task call
                self._pos_in_requires = idx
                task_call, end_pos = self._extract_task_call(text, idx)

                sub_result = self._execute_task_from_call(task_call, params)
                results.append(sub_result)

                # Update context
                context['_completed_tasks'] = set(self.executor.completed_tasks.keys())

                if not sub_result or sub_result.exit_code != 0:
                    # Task failed - we should stop executing
                    return results

                pos = end_pos
                continue

            # Check for 'for' loop
            if identifier == 'for':
                # Parse for loop
                self._pos_in_requires = idx
                loop_info = self._parse_for_loop(text, idx)

                if loop_info:
                    var_name, start_val, cond, update, loop_body, end_pos = loop_info

                    # Initialize loop variable
                    context[var_name] = start_val

                    while evaluator.evaluate(cond, context.copy()):
                        # Check if it's a task call in the loop body
                        if loop_body.strip().startswith(('task_', 'fail', 'fails')):
                            sub_result = self._execute_task_from_call(loop_body, params)
                            if sub_result and sub_result.exit_code != 0:
                                # Task failed
                                pass
                        else:
                            # Not a task call - could be condition or other expression
                            pass

                        # Update loop variable
                        if update.isnumeric():
                            context[var_name] += 1
                        else:
                            # Try to evaluate the update expression
                            try:
                                context[var_name] = evaluator.evaluate(update, context.copy())
                            except:
                                pass

                    pos = end_pos
                    continue

            # Check for 'while' loop
            if identifier == 'while':
                self._pos_in_requires = idx
                loop_info = self._parse_while_loop(text, idx)
                pos = loop_info.get('end_pos', idx)
                continue

            # Check for 'if' condition
            if identifier == 'if':
                self._pos_in_requires = idx
                if_info = self._parse_if_block(text, idx)
                pos = if_info.get('end_pos', idx)
                continue

            # Skip closing brace if at top level
            if text[pos] == '}' and pos > 0:
                # Check if this is the final closing brace
                break

            pos += 1

        return results

    def _extract_task_call(self, text: str, start: int) -> tuple:
        """Extract a task call from the requires block."""
        # Find the task name
        idx = start
        while idx < len(text) and (text[idx].isalnum() or text[idx] == '_'):
            idx += 1

        task_name = text[start:idx]

        # Skip whitespace
        while idx < len(text) and text[idx].isspace():
            idx += 1

        # Check if it's a function call (fails(task(...)))
        if text[idx:idx+5] == 'fails':
            # Find the closing paren
            depth = 0
            open_paren = text.find('(', idx)
            start_paren = open_paren
            depth = 1
            paren_idx = open_paren + 1

            while depth > 0 and paren_idx < len(text):
                if text[paren_idx] == '(':
                    depth += 1
                elif text[paren_idx] == ')':
                    depth -= 1
                paren_idx += 1

            task_call = text[idx:paren_idx]
            end_pos = paren_idx
            return task_call, end_pos

        # Extract parameters if present
        if idx < len(text) and text[idx] == '(':
            # Parse parameters
            depth = 1
            paren_idx = idx + 1

            while depth > 0 and paren_idx < len(text):
                if text[paren_idx] == '(':
                    depth += 1
                elif text[paren_idx] == ')':
                    depth -= 1
                paren_idx += 1

            task_call = text[idx:paren_idx]
            end_pos = paren_idx
            return task_call, end_pos

        # Just the task name
        task_call = task_name
        end_pos = idx
        return task_call, end_pos

    def _execute_task_from_call(self, call_str: str, parent_params: Dict[str, Any]) -> Optional[JobResult]:
        """Execute a sub-task based on a call string like 'task_name(1, x=2)' or just 'task_name'."""
        # Parse the call string
        paren_idx = call_str.find('(')

        if paren_idx == -1:
            # No parentheses - just a task name
            task_name = call_str.strip()
            call_params = {}
        else:
            task_name = call_str[:paren_idx].strip()
            if not call_str.endswith(')'):
                raise ValueError(f"Unclosed parenthesis in task call: {call_str}")

            args_str = call_str[paren_idx + 1:-1]

            if not args_str.strip():
                call_params = {}
            else:
                call_params = self._parse_call_args(args_str)

        if task_name not in self.tasks:
            raise ValueError(f"Unknown task: {task_name}")

        task = self.tasks[task_name]

        # Resolve parameters
        resolved_params = self._resolve_params_from_call(task, call_params)

        # Find parent job ID (if there's a currently running task)
        parent_job_id = None
        if hasattr(self, '_current_job_id'):
            parent_job_id = self._current_job_id

        # Execute the task
        return self.executor.execute_task(task, resolved_params, parent_job_id)

    def _parse_call_args(self, args_str: str) -> Dict[str, Any]:
        """Parse arguments from a task call string."""
        args = {}

        current = ""
        in_quotes = False
        quote_char = None
        depth = 0

        for ch in args_str:
            if ch in ('"', "'") and (not in_quotes or quote_char == ch):
                in_quotes = not in_quotes
                if in_quotes:
                    quote_char = ch
                else:
                    quote_char = None
                current += ch
            elif not in_quotes:
                if ch == '(' or ch == '[':
                    depth += 1
                    current += ch
                elif ch == ')' or ch == ']':
                    depth -= 1
                    current += ch
                elif ch == ',' and depth == 0:
                    if current.strip():
                        self._add_arg(current.strip(), args)
                    current = ""
                else:
                    current += ch
            else:
                current += ch

        if current.strip():
            self._add_arg(current.strip(), args)

        return args

    def _add_arg(self, arg: str, args: Dict[str, Any]):
        """Add a parsed argument to the args dict."""
        arg = arg.strip()

        if '=' in arg:
            key, val = arg.split('=', 1)
            key = key.strip()
            val = val.strip()

            # Remove quotes if present
            if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
                val = val[1:-1]

            # Type inference
            if val.isdigit():
                val = int(val)
            elif val.replace('.', '').isdigit():
                val = float(val)
            elif val.upper() in ('TRUE', 'FALSE'):
                val = val.upper() == 'TRUE'

            args[key] = val
        else:
            # Positional argument
            val = arg
            if val.isdigit():
                val = int(val)
            elif val.replace('.', '').isdigit():
                val = float(val)
            elif val.upper() in ('TRUE', 'FALSE'):
                val = val.upper() == 'TRUE'

            args[len(args)] = val

    def _parse_for_loop(self, text: str, start: int) -> Optional[dict]:
        """Parse a for loop statement."""
        # Format: for (type var = start; cond; update) { body }
        idx = start + 3  # Skip 'for'

        # Skip whitespace
        while idx < len(text) and text[idx].isspace():
            idx += 1

        if idx >= len(text) or text[idx] != '(':
            return None

        idx += 1  # Skip '('

        # Find the closing paren
        paren_depth = 1
        loop_start = idx

        while paren_depth > 0 and idx < len(text):
            if text[idx] == '(':
                paren_depth += 1
            elif text[idx] == ')':
                paren_depth -= 1
            idx += 1

        loop_header = text[loop_start:idx-1]
        parts = [p.strip() for p in loop_header.split(';')]

        if len(parts) != 3:
            return None

        # Parse init: type var = start
        init = parts[0].strip()
        init_parts = init.split('=')
        var_name = init_parts[0].split()[-1]  # Last word is the variable name
        start_val = init_parts[1].strip() if len(init_parts) > 1 else '0'

        # Handle start value
        try:
            start_val = int(start_val) if start_val.isdigit() else start_val
        except:
            pass

        # Parse condition
        cond = parts[1].strip()

        # Parse update
        update = parts[2].strip()

        # Find the body (inside braces)
        while idx < len(text) and text[idx].isspace():
            idx += 1

        if idx < len(text) and text[idx] == '{':
            body_idx = idx
            brace_depth = 1
            idx += 1

            while brace_depth > 0 and idx < len(text):
                if text[idx] == '{':
                    brace_depth += 1
                elif text[idx] == '}':
                    brace_depth -= 1
                idx += 1

            body = text[body_idx+1:idx-1].strip()
        else:
            body = ""

        return {
            'var_name': var_name,
            'start_val': start_val,
            'cond': cond,
            'update': update,
            'body': body,
            'end_pos': idx
        }

    def _parse_while_loop(self, text: str, start: int) -> dict:
        """Parse a while loop."""
        idx = start + 5  # Skip 'while'

        # Skip whitespace
        while idx < len(text) and text[idx].isspace():
            idx += 1

        # Find condition
        if idx >= len(text) or text[idx] != '(':
            return {'end_pos': idx}

        idx += 1  # Skip '('

        paren_depth = 1
        cond_start = idx

        while paren_depth > 0 and idx < len(text):
            if text[idx] == '(':
                paren_depth += 1
            elif text[idx] == ')':
                paren_depth -= 1
            idx += 1

        # Find body
        while idx < len(text) and text[idx].isspace():
            idx += 1

        if idx < len(text) and text[idx] == '{':
            body_idx = idx
            brace_depth = 1
            idx += 1

            while brace_depth > 0 and idx < len(text):
                if text[idx] == '{':
                    brace_depth += 1
                elif text[idx] == '}':
                    brace_depth -= 1
                idx += 1

        return {'end_pos': idx}

    def _parse_if_block(self, text: str, start: int) -> dict:
        """Parse an if/else block."""
        idx = start + 2  # Skip 'if'

        # Skip whitespace
        while idx < len(text) and text[idx].isspace():
            idx += 1

        # Find condition
        if idx >= len(text) or text[idx] != '(':
            return {'end_pos': idx}

        idx += 1  # Skip '('

        paren_depth = 1
        cond_start = idx

        while paren_depth > 0 and idx < len(text):
            if text[idx] == '(':
                paren_depth += 1
            elif text[idx] == ')':
                paren_depth -= 1
            idx += 1

        # Find body (then block)
        while idx < len(text) and text[idx].isspace():
            idx += 1

        if idx < len(text) and text[idx] == '{':
            body_idx = idx
            brace_depth = 1
            idx += 1

            while brace_depth > 0 and idx < len(text):
                if text[idx] == '{':
                    brace_depth += 1
                elif text[idx] == '}':
                    brace_depth -= 1
                idx += 1

        # Check for elif/else blocks
        remaining = text[idx:]

        # Parse elif blocks
        while remaining.startswith('elif'):
            idx += 4
            # Parse condition and body similarly to if
            self._skip_to_brace_close(remaining)

        # Parse else block
        if remaining.startswith('else'):
            idx += 4
            self._skip_to_brace_close(remaining)

        return {'end_pos': idx}

    def _skip_to_brace_close(self, text: str) -> int:
        """Skip to the closing brace."""
        brace_depth = 0
        pos = 0

        while pos < len(text):
            if text[pos] == '{':
                brace_depth += 1
            elif text[pos] == '}':
                brace_depth -= 1
                if brace_depth < 0:
                    return pos
            pos += 1

        return pos

    def execute(self, entry_spec: Optional[str] = None) -> int:
        """
        Execute the pipeline starting from the entry task.
        Returns exit code: 0 for success, 1 for entry task failure.
        """
        # Determine entry task
        entry_task_name, entry_params = self.resolve_entry_task(entry_spec)

        # Execute entry task
        result = self._execute_task(entry_task_name, entry_params, None)

        if result.exit_code != 0:
            # Entry task failed
            print(f"Entry task failed with exit code {result.exit_code}")
            return 1

        return 0

    def _execute_task(self, task_name: str, params: Dict[str, Any],
                     parent_job_id: Optional[int] = None) -> JobResult:
        """
        Execute a task, resolving dependencies first.
        """
        if task_name not in self.tasks:
            raise ValueError(f"Unknown task: {task_name}")

        task = self.tasks[task_name]

        # Set current job ID for dependency resolution
        self._current_job_id = parent_job_id

        # Resolve dependencies
        if task.requires:
            # Evaluate requires block
            self.resolve_dependencies(task, params)

        # Execute the task itself
        result = self.executor.execute_task(task, params, parent_job_id)

        return result

"""
Expression evaluator for success criteria and requires blocks.
Supports arithmetic, conditionals, string operations, and builtin functions.
"""
import re
from typing import Dict, Any, List, Optional, Tuple
from pathlib import Path


class EvaluationError(Exception):
    """Error evaluating expression."""
    pass


class ExpressionEvaluator:
    """
    Evaluates expressions in the pipeline language.
    Supports:
    - Variables, literals (int, float, string, bool)
    - Arithmetic (+, -, *, /, %, comparisons)
    - Logical operations (&&, ||, !)
    - String concatenation (%)
    - Arrays/indexing
    - Control flow (if/else, for loops, while loops)
    - Builtin functions (len, contains, equals, exists, fail)
    - Parameter substitution ($ params)
    """

    def __init__(self, workspace: Path, output_dir: Optional[Path] = None):
        self.workspace = workspace
        self.output_dir = output_dir
        self._functions = {
            'len': self._len_func,
            'contains': self._contains_func,
            'equals': self._equals_func,
            'exists': self._exists_func,
            'fail': self._fail_func,
        }

    def evaluate(self, expr: str, context: Dict[str, Any]) -> Any:
        """
        Evaluate an expression string with the given context.
        Returns the result of the evaluation.
        """
        if not expr or not expr.strip():
            return True  # Empty success criteria is considered True

        self._context = context.copy()
        self._result = None
        self._pos = 0
        self._expr = expr.strip()

        result = self._parse_expression()
        return result

    def parse_and_evaluate(self, expr: str, context: Dict[str, Any]) -> Any:
        """Parse and evaluate a block of statements."""
        self._context = context.copy()
        self._result = None
        self._pos = 0
        self._expr = expr.strip()

        return self._parse_block()

    # ============================================================
    # Parsing helpers
    # ============================================================

    def _skip_whitespace(self):
        """Skip whitespace characters."""
        while self._pos < len(self._expr) and self._expr[self._pos].isspace():
            self._pos += 1

    def _peek(self, offset: int = 0) -> str:
        """Look at the character at current position + offset."""
        idx = self._pos + offset
        if idx < len(self._expr):
            return self._expr[idx]
        return '\0'

    def _consume(self, expected: Optional[str] = None) -> str:
        """Consume and return the current character, optionally checking it."""
        self._skip_whitespace()
        if self._pos >= len(self._expr):
            if expected is None:
                return '\0'
            raise EvaluationError(f"Unexpected end of expression, expected '{expected}'")

        ch = self._expr[self._pos]
        if expected is not None and ch != expected:
            raise EvaluationError(f"Expected '{expected}', got '{ch}'")

        self._pos += 1
        return ch

    def _parse_identifier(self) -> str:
        """Parse an identifier (variable name, function name)."""
        self._skip_whitespace()

        if self._pos >= len(self._expr):
            raise EvaluationError("Expected identifier, found end of expression")

        start = self._pos
        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch.isalnum() or ch == '_':
                self._pos += 1
            else:
                break

        if self._pos == start:
            raise EvaluationError(f"Expected identifier, found '{self._expr[self._pos]}'")

        return self._expr[start:self._pos]

    def _parse_string(self) -> str:
        """Parse a quoted string."""
        self._skip_whitespace()
        if self._pos >= len(self._expr):
            raise EvaluationError("Expected string, found end of expression")

        quote = self._expr[self._pos]
        if quote not in ('"', "'"):
            raise EvaluationError(f"Expected string, found '{quote}'")

        self._pos += 1
        result = []

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '\\':
                # Handle escape sequences
                self._pos += 1
                if self._pos < len(self._expr):
                    esc = self._expr[self._pos]
                    if esc == 'n':
                        result.append('\n')
                    elif esc == 't':
                        result.append('\t')
                    elif esc == 'r':
                        result.append('\r')
                    elif esc in ('"', "'", '\\'):
                        result.append(esc)
                    else:
                        result.append(esc)
                    self._pos += 1
                else:
                    result.append('\\')
            elif ch == quote:
                self._pos += 1
                break
            else:
                result.append(ch)
                self._pos += 1

        return ''.join(result)

    def _parse_number(self) -> Any:
        """Parse a number (int or float)."""
        self._skip_whitespace()

        start = self._pos
        has_decimal = False

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '.' and not has_decimal:
                has_decimal = True
                self._pos += 1
            elif ch.isdigit():
                self._pos += 1
            else:
                break

        if self._pos == start:
            raise EvaluationError(f"Expected number, found '{self._expr[self._pos]}'")

        num_str = self._expr[start:self._pos]
        if has_decimal:
            return float(num_str)
        return int(num_str)

    def _parse_list(self) -> List[Any]:
        """Parse a list literal [a, b, c]."""
        self._skip_whitespace()
        if self._peek() != '[':
            raise EvaluationError(f"Expected '[', found '{self._peek()}'")

        self._pos += 1  # consume '['

        result = []

        if self._peek() == ']':
            self._pos += 1
            return result

        while self._pos < len(self._expr):
            self._skip_whitespace()
            value = self._parse_expression()
            result.append(value)

            self._skip_whitespace()
            if self._peek() == ',':
                self._pos += 1
                continue
            elif self._peek() == ']':
                self._pos += 1
                break
            else:
                raise EvaluationError(f"Expected ',' or ']', found '{self._peek()}'")

        return result

    # ============================================================
    # Expression parsing (recursive descent)
    # ============================================================

    def _parse_expression(self) -> Any:
        """Parse an expression."""
        self._skip_whitespace()
        return self._parse_or()

    def _parse_or(self) -> Any:
        """Parse OR expressions (&&, ||)."""
        left = self._parse_and()

        self._skip_whitespace()
        while self._peek() == '&' and self._peek(1) == '&':
            self._pos += 2  # consume '&&'
            right = self._parse_and()
            left = left and self._to_bool(right)
            self._skip_whitespace()

        while self._peek() == '|' and self._peek(1) == '|':
            self._pos += 2  # consume '||'
            right = self._parse_and()
            left = left or self._to_bool(right)
            self._skip_whitespace()

        return left

    def _parse_and(self) -> Any:
        """Parse AND expressions."""
        left = self._parse_equality()

        self._skip_whitespace()
        while self._peek() == '&' and self._peek(1) == '&':
            self._pos += 2
            right = self._parse_equality()
            left = left and self._to_bool(right)
            self._skip_whitespace()

        return left

    def _parse_equality(self) -> Any:
        """Parse equality expressions (==, !=)."""
        left = self._parse_comparison()

        self._skip_whitespace()
        while self._peek() == '=' and self._peek(1) == '=':
            self._pos += 2
            right = self._parse_comparison()
            left = left == right
            self._skip_whitespace()

        while self._peek() == '!' and self._peek(1) == '=':
            self._pos += 2
            right = self._parse_comparison()
            left = left != right
            self._skip_whitespace()

        return left

    def _parse_comparison(self) -> Any:
        """Parse comparison expressions (<, >, <=, >=)."""
        left = self._parse_additive()

        self._skip_whitespace()
        while True:
            if self._peek() == '<' and self._peek(1) == '=':
                self._pos += 2
                right = self._parse_additive()
                left = left <= right
            elif self._peek() == '>':
                if self._peek(1) == '=':
                    self._pos += 2
                    right = self._parse_additive()
                    left = left >= right
                else:
                    self._pos += 1
                    right = self._parse_additive()
                    left = left > right
            elif self._peek() == '<':
                self._pos += 1
                right = self._parse_additive()
                left = left < right
            else:
                break

            self._skip_whitespace()

        return left

    def _parse_additive(self) -> Any:
        """Parse addition and subtraction."""
        left = self._parse_term()

        self._skip_whitespace()
        while self._peek() in ('+', '-'):
            op = self._peek()
            self._pos += 1
            right = self._parse_term()

            if op == '+':
                left = left + right
            else:
                left = left - right

            self._skip_whitespace()

        return left

    def _parse_term(self) -> Any:
        """Parse multiplication, division, and modulo."""
        left = self._parse_factor()

        self._skip_whitespace()
        while self._peek() in ('*', '/', '%'):
            op = self._peek()
            self._pos += 1
            right = self._parse_factor()

            if op == '*':
                left = left * right
            elif op == '/':
                left = left / right
            elif op == '%':
                left = left % right

            self._skip_whitespace()

        return left

    def _parse_factor(self) -> Any:
        """Parse unary operators and primary expressions."""
        self._skip_whitespace()

        # Handle unary + and -
        if self._peek() == '+':
            self._pos += 1
            return self._parse_factor()
        elif self._peek() == '-':
            self._pos += 1
            return -self._parse_number() if self._expr[self._pos].isdigit() else -self._parse_factor()
        elif self._peek() == '!':
            self._pos += 1
            value = self._parse_factor()
            return not self._to_bool(value)

        return self._parse_primary()

    def _parse_primary(self) -> Any:
        """Parse primary expressions (literals, variables, function calls, etc.)."""
        self._skip_whitespace()

        # Handle parameter substitution ${...}
        if self._peek() == '$' and self._peek(1) == '{':
            return self._parse_param_substitution()

        # String literal
        if self._peek() in ('"', "'"):
            return self._parse_string()

        # List literal
        if self._peek() == '[':
            return self._parse_list()

        # Number
        if self._peek().isdigit() or self._peek() == '.':
            return self._parse_number()

        # True/False
        if self._expr.startswith('TRUE', self._pos):
            self._pos += 4
            return True
        if self._expr.startswith('FALSE', self._pos):
            self._pos += 5
            return False

        # Function call
        identifier = self._parse_identifier()
        self._skip_whitespace()
        if self._peek() == '(':
            return self._parse_function_call(identifier)

        # Check if it's a variable
        if identifier in self._context:
            return self._context[identifier]

        # It's an identifier (string value)
        return identifier

    def _parse_param_substitution(self) -> str:
        """Parse ${params.x} or ${workspace}."""
        if not (self._peek() == '$' and self._peek(1) == '{'):
            raise EvaluationError("Expected ${...}")

        self._pos += 2  # consume ${'
        start = self._pos

        depth = 0
        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '{':
                depth += 1
            elif ch == '}':
                if depth == 0:
                    break
                depth -= 1
            self._pos += 1

        inner = self._expr[start:self._pos]

        if inner.startswith('params.'):
            param_name = inner[7:]
            if param_name in self._context.get('params', {}):
                return str(self._context['params'][param_name])
            else:
                return f"${{params.{param_name}}}"
        elif inner == 'workspace':
            return str(self.workspace.resolve()) if self.workspace else ""
        elif inner == 'output':
            return str(self.output_dir) if self.output_dir else ""
        else:
            # Try to resolve as variable
            if inner in self._context:
                return str(self._context[inner])
            return f"${{{inner}}}"

    def _parse_function_call(self, func_name: str) -> Any:
        """Parse a function call: func_name(arg1, arg2, ...)."""
        if self._peek() != '(':
            raise EvaluationError(f"Expected '(', found '{self._peek()}'")

        self._pos += 1  # consume '('
        self._skip_whitespace()

        args = []

        if self._peek() == ')':
            self._pos += 1
        else:
            while True:
                self._skip_whitespace()
                arg = self._parse_expression()
                args.append(arg)

                self._skip_whitespace()
                if self._peek() == ',':
                    self._pos += 1
                    continue
                elif self._peek() == ')':
                    self._pos += 1
                    break
                else:
                    raise EvaluationError(f"Expected ',' or ')', found '{self._peek()}'")

        # Execute the function
        if func_name not in self._functions:
            raise EvaluationError(f"Unknown function: {func_name}")

        return self._functions[func_name](args)

    def _parse_block(self) -> Any:
        """Parse a block of statements."""
        self._result = None

        while self._pos < len(self._expr):
            self._skip_whitespace()

            if self._pos >= len(self._expr):
                break

            # Check for variable declaration
            ident = self._parse_identifier()
            self._skip_whitespace()
            if self._peek() == ':':
                # This is a varDecl
                self._pos += 1
                self._skip_whitespace()
                type_str = self._parse_identifier()
                self._skip_whitespace()
                self._consume('=')
                value = self._parse_expression()
                self._context[ident] = value
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                continue

            # Check for for loop
            if ident == 'for':
                self._skip_whitespace()
                self._consume('(')
                # Parse forInit
                loop_var_type = self._parse_identifier()
                loop_var = self._parse_identifier()
                self._skip_whitespace()
                self._consume('=')
                start_val = self._parse_expression()
                self._skip_whitespace()
                self._consume(';')
                cond = self._parse_expression()
                self._skip_whitespace()
                self._consume(';')
                update = self._parse_identifier()
                self._skip_whitespace()
                self._consume('=')
                update_expr = self._parse_expression()
                self._skip_whitespace()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                loop_body = self._collect_block()

                # Execute loop
                self._context[loop_var] = start_val
                while self._evaluate_condition(cond):
                    # Execute body
                    body_context = self._context.copy()
                    evaluator = ExpressionEvaluator(self.workspace, self.output_dir)
                    evaluator._context = body_context
                    evaluator.parse_and_evaluate(loop_body, body_context)
                    self._context.update(evaluator._context)

                    # Update loop variable
                    if update == loop_var:
                        if isinstance(update_expr, int):
                            self._context[loop_var] += 1
                        else:
                            self._context[loop_var] = update_expr
                    else:
                        # Handle increment
                        if self._peek() in ('++', '--'):
                            self._pos += 2

                # After loop, read closing brace
                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1
                continue

            # Check for while loop
            if ident == 'while':
                self._skip_whitespace()
                self._consume('(')
                cond = self._parse_expression()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                loop_body = self._collect_block()

                # Execute loop
                while self._evaluate_condition(cond):
                    body_context = self._context.copy()
                    evaluator = ExpressionEvaluator(self.workspace, self.output_dir)
                    evaluator._context = body_context
                    evaluator.parse_and_evaluate(loop_body, body_context)
                    self._context.update(evaluator._context)

                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1
                continue

            # Check for if statement
            if ident == 'if':
                self._skip_whitespace()
                self._consume('(')
                cond = self._parse_expression()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                then_body = self._collect_block()

                if self._to_bool(self.evaluate(cond, self._context)):
                    evaluator = ExpressionEvaluator(self.workspace, self.output_dir)
                    evaluator._context = self._context.copy()
                    evaluator.parse_and_evaluate(then_body, evaluator._context)
                    self._context.update(evaluator._context)

                # Consume closing brace
                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1

                # Check for elif/else
                while True:
                    self._skip_whitespace()
                    if self._expr.startswith('elif', self._pos):
                        self._pos += 4
                        self._skip_whitespace()
                        self._consume('(')
                        elif_cond = self._parse_expression()
                        self._consume(')')
                        self._skip_whitespace()
                        self._consume('{')
                        elif_body = self._collect_block()

                        if not self._result and self._to_bool(self.evaluate(elif_cond, self._context)):
                            evaluator = ExpressionEvaluator(self.workspace, self.output_dir)
                            evaluator._context = self._context.copy()
                            evaluator.parse_and_evaluate(elif_body, evaluator._context)
                            self._context.update(evaluator._context)

                        self._skip_whitespace()
                        if self._peek() == '}':
                            self._pos += 1
                    elif self._expr.startswith('else', self._pos):
                        self._pos += 4
                        self._skip_whitespace()
                        self._consume('{')
                        else_body = self._collect_block()

                        if not self._result:
                            evaluator = ExpressionEvaluator(self.workspace, self.output_dir)
                            evaluator._context = self._context.copy()
                            evaluator.parse_and_evaluate(else_body, evaluator._context)
                            self._context.update(evaluator._context)

                        self._skip_whitespace()
                        if self._peek() == '}':
                            self._pos += 1
                    else:
                        break

                continue

            # Check for return statement
            if ident == 'return':
                value = self._parse_expression()
                self._result = self._to_bool(value)
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return self._result

            # Check for break
            if ident == 'break':
                self._result = True
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return self._result

            # Check for continue
            if ident == 'continue':
                self._result = True
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return self._result

            # Check for function call (top-level statement)
            self._skip_whitespace()
            if self._peek() == '(':
                # This is a function call that has side effects
                func_result = self._parse_function_call(ident)
                if isinstance(func_result, bool) and not func_result:
                    self._result = False
                    return self._result
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                continue

            # Try to parse as expression
            self._pos -= len(ident)
            value = self._parse_expression()
            self._skip_whitespace()
            if self._peek() == ';':
                self._pos += 1

        return self._result if self._result is not None else True

    def _collect_block(self) -> str:
        """Collect a block of text until matching brace."""
        start = self._pos
        depth = 0

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '{':
                depth += 1
            elif ch == '}':
                depth -= 1
                if depth < 0:
                    break
            self._pos += 1

        return self._expr[start:self._pos]

    def _evaluate_condition(self, expr: Any) -> bool:
        """Evaluate a condition to boolean."""
        return self._to_bool(expr)

    def _to_bool(self, value: Any) -> bool:
        """Convert a value to boolean."""
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)):
            return value != 0
        if isinstance(value, str):
            return value.lower() in ('true', 'yes', '1', 't')
        if isinstance(value, list):
            return len(value) > 0
        return value is not None

    def _len_func(self, args: List) -> int:
        """Builtin len function."""
        if len(args) != 1:
            raise EvaluationError(f"len() takes exactly 1 argument, got {len(args)}")
        if isinstance(args[0], list):
            return len(args[0])
        raise EvaluationError(f"len() requires a list, got {type(args[0])}")

    def _contains_func(self, args: List) -> bool:
        """Builtin contains function."""
        if len(args) != 2:
            raise EvaluationError(f"contains() takes exactly 2 arguments, got {len(args)}")

        arg1, arg2 = args

        if isinstance(arg1, str) and isinstance(arg2, str):
            return arg2 in arg1

        if isinstance(arg1, list) and isinstance(arg2, str):
            return arg2 in arg1

        # Try to read file contents
        if isinstance(arg1, str):
            # arg1 is a file path, arg2 is what we're looking for
            path = Path(arg1)
            if path.exists():
                try:
                    with open(path, 'r') as f:
                        content = f.read()
                    return arg2 in content
                except:
                    return False

        return False

    def _equals_func(self, args: List) -> bool:
        """Builtin equals function."""
        if len(args) != 2:
            raise EvaluationError(f"equals() takes exactly 2 arguments, got {len(args)}")

        arg1, arg2 = args

        if isinstance(arg1, str):
            # Could be a special value like "stdout", "stderr", "exit_code"
            path = Path(arg1)
            if path.exists():
                try:
                    with open(path, 'r') as f:
                        return f.read().strip() == str(arg2)
                except:
                    return False

        return str(arg1) == str(arg2)

    def _exists_func(self, args: List) -> bool:
        """Builtin exists function."""
        if len(args) != 1:
            raise EvaluationError(f"exists() takes exactly 1 argument, got {len(args)}")

        path = Path(args[0])
        return path.exists()

    def _fail_func(self, args: List) -> bool:
        """Builtin fail function - checks if a task failed."""
        if len(args) != 1:
            raise EvaluationError(f"fail() takes exactly 1 argument, got {len(args)}")

        # This is a special function - we store it for later processing
        # in the requires block evaluation
        task_name = str(args[0])
        self._context['_failed_tasks'] = self._context.get('_failed_tasks', [])
        self._context['_failed_tasks'].append(task_name)
        # For now, assume it's checking if a task failed
        # In the requires block context, we'll use this differently
        return task_name in self._context.get('_completed_tasks', [])

